    52→func (m *updateDashboardUIDPanelIDMigration) Exec(sess *xorm.Session, mg *migrator.Migrator) error {
    53→	var results []struct {
    54→		ID          int64             `xorm:"id"`
    55→		Annotations map[string]string `xorm:"annotations"`
    56→	}
    57→	if err := sess.SQL(`SELECT id, annotations FROM alert_rule`).Find(&results); err != nil {
    58→		return fmt.Errorf("failed to get annotations for all alert rules: %w", err)
    59→	}
    60→	for _, next := range results {
    61→		var (
    62→			dashboardUID *string
    63→			panelID      *int64
    64→		)
    65→		if s, ok := next.Annotations[ngmodels.DashboardUIDAnnotation]; ok {
    66→			dashboardUID = &s
    67→		}
    68→		if s, ok := next.Annotations[ngmodels.PanelIDAnnotation]; ok {
    69→			i, err := strconv.ParseInt(s, 10, 64)
    70→			if err != nil {
    71→				return fmt.Errorf("the %s annotation does not contain a valid Panel ID: %w", ngmodels.PanelIDAnnotation, err)
    72→			}
    73→			panelID = &i
    74→		}
    75→		// We do not want to set panel_id to a non-nil value when dashboard_uid is nil
    76→		// as panel_id is not unique and so cannot be queried without its dashboard_uid.
    77→		// This can happen where users have deleted the dashboard_uid annotation but kept
    78→		// the panel_id annotation.
    79→		if dashboardUID != nil {
    80→			if _, err := sess.Exec(`UPDATE alert_rule SET dashboard_uid = ?, panel_id = ? WHERE id = ?`,
    81→				dashboardUID,
    82→				panelID,
    83→				next.ID); err != nil {
    84→				return fmt.Errorf("failed to set dashboard_uid and panel_id for alert rule: %w", err)
    85→			}
    86→		}
    87→	}
    88→	return nil
    89→}
