   105→
   106→func (u *upgradeNgAlerting) Exec(sess *xorm.Session, migrator *migrator.Migrator) error {
   107→	firstOrgId, err := u.updateAlertConfigurations(sess, migrator)
   108→	if err != nil {
   109→		return err
   110→	}
   111→	u.updateAlertmanagerFiles(firstOrgId, migrator)
   112→	return nil
   113→}
   114→
   115→func (u *upgradeNgAlerting) updateAlertConfigurations(sess *xorm.Session, migrator *migrator.Migrator) (int64, error) {
   116→	// if there are records with org_id == 0 then the feature flag was enabled before 8.2 that introduced org separation.
   117→	// if feature is enabled in 8.2 the migration "AddDashAlertMigration", which is effectively different from what was run in 8.1.x and earlier versions,
   118→	// will handle organizations correctly, and, therefore, nothing needs to be fixed
   119→	count, err := sess.Table(&AlertConfiguration{}).Where("org_id = 0").Count()
   120→	if err != nil {
   121→		return 0, fmt.Errorf("failed to query table alert_configuration: %w", err)
   122→	}
   123→	if count == 0 {
   124→		return 0, nil // NOTHING TO DO
   125→	}
   126→
   127→	orgs := make([]int64, 0)
   128→	// get all org IDs sorted in ascending order
   129→	if err = sess.Table("org").OrderBy("id").Cols("id").Find(&orgs); err != nil {
   130→		return 0, fmt.Errorf("failed to query table org: %w", err)
   131→	}
   132→	if len(orgs) == 0 { // should not really happen
   133→		migrator.Logger.Info("No organizations are found. Nothing to migrate")
   134→		return 0, nil
   135→	}
   136→
   137→	firstOrg := orgs[0]
   138→
   139→	// assigning all configurations to the first org because 0 does not usually point to any
   140→	migrator.Logger.Info("Assigning all existing records from alert_configuration to the first organization", "org", firstOrg)
   141→	_, err = sess.Cols("org_id").Where("org_id = 0").Update(&AlertConfiguration{OrgID: firstOrg})
   142→	if err != nil {
   143→		return 0, fmt.Errorf("failed to update org_id for all rows in the table alert_configuration: %w", err)
   144→	}
   145→
   146→	// if there is a single organization it is safe to assume that all configurations belong to it.
   147→	if len(orgs) == 1 {
   148→		return firstOrg, nil
   149→	}
   150→	// if there are many organizations we cannot safely assume what organization an alert_configuration belongs to.
   151→	// Therefore, we apply the default configuration to all organizations. The previous version could be restored if needed.
   152→	migrator.Logger.Warn("Detected many organizations. The current alertmanager configuration will be replaced by the default one")
   153→	configs := make([]*AlertConfiguration, 0, len(orgs))
   154→	for _, org := range orgs {
   155→		configs = append(configs, &AlertConfiguration{
   156→			AlertmanagerConfiguration: migrator.Cfg.UnifiedAlerting.DefaultConfiguration,
   157→			// Since we are migration for a snapshot of the code, it is always going to migrate to
   158→			// the v1 config.
   159→			ConfigurationVersion: "v1",
   160→			OrgID:                org,
   161→		})
   162→	}
   163→
   164→	_, err = sess.InsertMulti(configs)
   165→	if err != nil {
   166→		return 0, fmt.Errorf("failed to add default alertmanager configurations to every organization: %w", err)
   167→	}
   168→	return 0, nil
   169→}
   170→
   171→// updateAlertmanagerFiles scans the existing alerting directory '<data_dir>/alerting' for known files.
   172→// If argument 'orgId' is not 0 updateAlertmanagerFiles moves all known files to the directory <data_dir>/alerting/<orgId>.
   173→// Otherwise, it deletes those files.
   174→// pre-8.2 version put all configuration files into the root of alerting directory. Since 8.2 configuration files are put in organization specific directory
   175→func (u *upgradeNgAlerting) updateAlertmanagerFiles(orgId int64, migrator *migrator.Migrator) {
   176→	knownFiles := map[string]any{"__default__.tmpl": nil, "silences": nil, "notifications": nil}
   177→	alertingDir := filepath.Join(migrator.Cfg.DataPath, "alerting")
   178→
   179→	// do not fail if something goes wrong because these files are not used anymore. the worst that can happen is that we leave some leftovers behind
   180→	deleteFile := func(fileName string) {
   181→		path := filepath.Join(alertingDir, fileName)
   182→		migrator.Logger.Info("Deleting alerting configuration file", "file", fileName)
   183→		err := os.Remove(path)
   184→		if err != nil {
   185→			migrator.Logger.Warn("Failed to delete file", "file", path, "error", err)
   186→		}
   187→	}
   188→
   189→	moveFile := func(fileName string) {
   190→		alertingOrgDir := filepath.Join(alertingDir, strconv.FormatInt(orgId, 10))
   191→		if err := os.MkdirAll(alertingOrgDir, 0750); err != nil {
   192→			migrator.Logger.Error("Failed to create alerting directory for organization. Skip moving the file and delete it instead", "target_dir", alertingOrgDir, "org_id", orgId, "error", err, "file", fileName)
   193→			deleteFile(fileName)
   194→			return
   195→		}
   196→		err := os.Rename(filepath.Join(alertingDir, fileName), filepath.Join(alertingOrgDir, fileName))
   197→		if err != nil {
   198→			migrator.Logger.Error("Failed to move alertmanager configuration file to organization.", "source_dir", alertingDir, "target_dir", alertingOrgDir, "org_id", orgId, "error", err, "file", fileName)
   199→			deleteFile(fileName)
   200→		}
   201→	}
   202→
   203→	entries, err := os.ReadDir(alertingDir)
   204→	if err != nil {
   205→		if !os.IsNotExist(err) {
   206→			keys := make([]string, 0, len(knownFiles))
   207→			for key := range knownFiles {
   208→				keys = append(keys, key)
   209→			}
   210→			migrator.Logger.Warn("Failed to clean up alerting directory. There may be files that are not used anymore.", "path", alertingDir, "files_to_delete", keys, "error", err)
   211→		}
   212→	}
   213→
   214→	for _, entry := range entries {
   215→		_, known := knownFiles[entry.Name()]
   216→		if known {
   217→			if orgId == 0 {
   218→				deleteFile(entry.Name())
   219→			} else {
   220→				moveFile(entry.Name())
   221→			}
   222→		}
   223→	}
   224→}
   225→
   226→func (u *upgradeNgAlerting) SQL(migrator.Dialect) string {
   227→	return codeMigration
   228→}
